 namespace WPAICG\Images\Providers\Google; if (!defined('ABSPATH')) { exit; } class GoogleVideoPayloadFormatter { public static function format(string $prompt, array $options): array { $model_id = $options['model'] ?? ''; $payload = []; $instance = [ 'prompt' => $prompt ]; $payload = [ 'instances' => [$instance] ]; $parameters = []; if (isset($options['aspect_ratio'])) { $parameters['aspectRatio'] = $options['aspect_ratio']; } if (isset($options['negative_prompt']) && !empty($options['negative_prompt'])) { $parameters['negativePrompt'] = $options['negative_prompt']; } if (isset($options['person_generation'])) { $parameters['personGeneration'] = $options['person_generation']; } if (!empty($parameters)) { $payload['parameters'] = $parameters; } return $payload; } } 